    uint8_t carry_in = cpu->flags.C ? 1u : 0u;
    uint16_t subtrahend = (uint16_t)value + (uint16_t)carry_in;
    uint16_t result = (uint16_t)a - subtrahend;
    uint8_t out = (uint8_t)(result & 0xFF);
