    cpu->flags.Z = (out == 0);
    cpu->flags.S = ((out & 0x80) != 0);
    cpu->flags.H = (true);
    cpu->flags.P = (cpu_parity(out));
    cpu->flags.C = (false);
    cpu->flags.N = (false);
