/* INC_IXD - arithmetic */
static void inst_INC_IXD(CPUState *cpu, DecodedInstruction *inst) {
    uint16_t addr = (uint16_t)(cpu->ix + (int8_t)inst->disp);
    uint8_t old = z80_read_byte(cpu, addr);
    uint8_t value = (uint8_t)(old + 1u);
    z80_write_byte(cpu, addr, value);
    cpu->flags.Z = (value == 0);
    cpu->flags.S = ((value & 0x80) != 0);
    cpu->flags.H = (((old & 0x0F) + 1u) > 0x0F);
    cpu->flags.P = (old == 0x7F);
    cpu->flags.N = (false);
    cpu->flags.raw = (uint8_t)((cpu->flags.raw & (uint8_t)(~0x28u)) | ((uint8_t)(old + 1u) & 0x28u));
}

/* DEC_IXD - arithmetic */
static void inst_DEC_IXD(CPUState *cpu, DecodedInstruction *inst) {
    uint16_t addr = (uint16_t)(cpu->ix + (int8_t)inst->disp);
    uint8_t old = z80_read_byte(cpu, addr);
    uint8_t value = (uint8_t)(old - 1u);
    z80_write_byte(cpu, addr, value);
    cpu->flags.Z = (value == 0);
    cpu->flags.S = ((value & 0x80) != 0);
    cpu->flags.H = ((old & 0x0F) == 0x00);
    cpu->flags.P = (old == 0x80);
    cpu->flags.N = (true);
    cpu->flags.raw = (uint8_t)((cpu->flags.raw & (uint8_t)(~0x28u)) | ((uint8_t)(old - 1u) & 0x28u));
}

