/* HALT - control */
static void inst_HALT(CPUState *cpu, DecodedInstruction *inst) {
    cpu->halted = true;
}

/* LD_R_R - data_transfer */
static void inst_LD_R_R(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t rs = inst->rs & 0x07;
    uint8_t rd = inst->rd & 0x07;
    uint8_t val = 0;

    if (rs == 0) val = cpu->registers[REG_B];
    else if (rs == 1) val = cpu->registers[REG_C];
    else if (rs == 2) val = cpu->registers[REG_D];
    else if (rs == 3) val = cpu->registers[REG_E];
    else if (rs == 4) val = cpu->registers[REG_H];
    else if (rs == 5) val = cpu->registers[REG_L];
    else if (rs == 6) {
    uint16_t hl = (uint16_t)((cpu->registers[REG_H] << 8) | cpu->registers[REG_L]);
    val = z80_read_byte(cpu, hl);
    } else {
    val = cpu->registers[REG_A];
    }

    if (rd == 0) cpu->registers[REG_B] = val;
    else if (rd == 1) cpu->registers[REG_C] = val;
    else if (rd == 2) cpu->registers[REG_D] = val;
    else if (rd == 3) cpu->registers[REG_E] = val;
    else if (rd == 4) cpu->registers[REG_H] = val;
    else if (rd == 5) cpu->registers[REG_L] = val;
    else if (rd == 6) {
    uint16_t hl = (uint16_t)((cpu->registers[REG_H] << 8) | cpu->registers[REG_L]);
    z80_write_byte(cpu, hl, val);
    } else {
    cpu->registers[REG_A] = val;
    }
}

/* ADD_A_R - arithmetic */
static void inst_ADD_A_R(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t r = inst->r & 0x07;
    uint8_t val = 0;
    if (r == 0) val = cpu->registers[REG_B];
    else if (r == 1) val = cpu->registers[REG_C];
    else if (r == 2) val = cpu->registers[REG_D];
    else if (r == 3) val = cpu->registers[REG_E];
    else if (r == 4) val = cpu->registers[REG_H];
    else if (r == 5) val = cpu->registers[REG_L];
    else if (r == 6) {
    uint16_t hl = (uint16_t)((cpu->registers[REG_H] << 8) | cpu->registers[REG_L]);
    val = z80_read_byte(cpu, hl);
    } else {
    val = cpu->registers[REG_A];
    }
    uint8_t a = cpu->registers[REG_A];
    uint16_t result = (uint16_t)a + (uint16_t)val;
    uint8_t result8 = (uint8_t)(result & 0xFF);
    cpu->registers[REG_A] = result8;
    cpu->flags.C = (result > 0xFF);
    cpu->flags.H = (((a & 0x0F) + (val & 0x0F)) > 0x0F);
    cpu->flags.P = (((~(a ^ val)) & (a ^ result8) & 0x80) != 0);
    cpu->flags.Z = (result8 == 0);
    cpu->flags.S = ((result8 & 0x80) != 0);
    cpu->flags.N = (false);
    cpu->flags.raw = (uint8_t)((cpu->flags.raw & (uint8_t)(~0x28u)) | (result8 & 0x28u));
}

