int z80_load_rom(CPUState *cpu, const char *filename, uint16_t address) {
    if (!cpu || !filename || !filename[0]) return -1;
    FILE *f = fopen(filename, "rb");
    if (!f) return -1;
    
    fseek(f, 0, SEEK_END);
    long size = ftell(f);
    fseek(f, 0, SEEK_SET);
    if (size < 0) {
        fclose(f);
        return -1;
    }
    
    if (address + size > cpu->memory_size) {
        fclose(f);
        return -1;
    }
    
    size_t read_len = fread(&cpu->memory[address], 1, (size_t)size, f);
    fclose(f);
    if (read_len != (size_t)size) return -1;
    snprintf(
        cpu->loaded_rom_debug,
        sizeof(cpu->loaded_rom_debug),
        "name=direct path=%s",
        filename
    );
    return 0;
}
int z80_load_system_roms(CPUState *cpu, const char *system_base_dir) {
    if (!cpu) return -1;
    (void)system_base_dir;
    cpu->loaded_rom_debug[0] = '\0';
    return 0;
}

int z80_load_cartridge_rom(CPUState *cpu, const char *path) {
    FILE *f;
    long file_size;
    uint8_t *buf;
    ComponentState_sg_cart0 *comp;
    size_t read_len;

    if (!cpu || !path || !path[0]) return -1;
    comp = &cpu->comp_sg_cart0;
    f = fopen(path, "rb");
    if (!f) return -1;
    if (fseek(f, 0, SEEK_END) != 0) { fclose(f); return -1; }
    file_size = ftell(f);
    if (file_size < 0) { fclose(f); return -1; }
    if (fseek(f, 0, SEEK_SET) != 0) { fclose(f); return -1; }
    buf = (uint8_t *)malloc((size_t)file_size);
    if (!buf) { fclose(f); return -1; }
    read_len = fread(buf, 1, (size_t)file_size, f);
    fclose(f);
    if (read_len != (size_t)file_size) { free(buf); return -1; }
    if (comp->rom_data != NULL) {
        free(comp->rom_data);
        comp->rom_data = NULL;
    }
    comp->rom_data = buf;
    comp->rom_size = (uint32_t)file_size;
    snprintf(
        cpu->loaded_rom_debug,
        sizeof(cpu->loaded_rom_debug),
        "name=sg_cart0 path=%s",
        path
    );
    return 0;
}


/* ===== Memory Access ===== */
uint8_t z80_read_byte(CPUState *cpu, uint16_t addr) {
    {
        ComponentState_sg_cart0 *comp = &cpu->comp_sg_cart0;
        cpu->active_component_id = "sg_cart0";
        if (addr < 0xC000u) {
            if (comp->rom_data == NULL || comp->rom_size == 0u) {
                return 0xFFu;
            }
            {
                uint32_t off = (uint32_t)addr;
                if (off < comp->rom_size) {
                    return comp->rom_data[off];
                }
            }
            return 0xFFu;
        }
    }
    if (addr >= cpu->memory_size) {
        cpu->error_code = CPU_ERROR_INVALID_MEMORY;
        return 0xFF;
    }
    return cpu->memory[addr];
}

void z80_write_byte(CPUState *cpu, uint16_t addr, uint8_t value) {

    if (addr >= cpu->memory_size) {
        cpu->error_code = CPU_ERROR_INVALID_MEMORY;
        return;
    }
    /* Ignore writes to read-only region: CART_ROM_48K */
    if (addr < 0xC000u) {
        return;
    }
    cpu->memory[addr] = value;
}

uint16_t z80_read_word(CPUState *cpu, uint16_t addr) {
    uint16_t lo = z80_read_byte(cpu, addr);
    uint16_t hi = z80_read_byte(cpu, (uint16_t)(addr + 1u));
    return (uint16_t)(lo | (hi << 8));
}

void z80_write_word(CPUState *cpu, uint16_t addr, uint16_t value) {
    z80_write_byte(cpu, addr, (uint8_t)(value & 0xFFu));
    z80_write_byte(cpu, (uint16_t)(addr + 1u), (uint8_t)((value >> 8) & 0xFFu));
}

/* ===== Port I/O ===== */
uint8_t z80_read_port(CPUState *cpu, uint16_t port) {


    uint8_t value = (port < cpu->port_size) ? cpu->port_memory[port] : 0xFF;
    {
        ComponentState_sg_vdp0 *comp = &cpu->comp_sg_vdp0;
        cpu->active_component_id = "sg_vdp0";
        uint8_t *vram = comp->vram;
        if (vram == NULL) { value = 0xFFu; return value; }
        uint8_t p = (uint8_t)(((uint16_t)port) & 0x00C1u);
        if (p == 0x80u) {
            value = comp->read_buffer;
            comp->read_buffer = vram[(uint16_t)(comp->vdp_addr & 0x3FFFu)];
            comp->vdp_addr = (uint16_t)((comp->vdp_addr + 1u) & 0x3FFFu);
        } else if (p == 0x81u) {
            value = comp->status;
            comp->status = (uint8_t)(comp->status & 0x7Fu);
            comp->control_phase = 0u;
        }
    }
    {
        ComponentState_sg_joy0 *comp = &cpu->comp_sg_joy0;
        cpu->active_component_id = "sg_joy0";
        uint8_t p = (uint8_t)(((uint16_t)port) & 0xC1u);
        uint8_t joy1 = (uint8_t)cpu_component_call(cpu, "sg_joy0", "joy1_read", NULL, 0);
        uint8_t joy2 = (uint8_t)cpu_component_call(cpu, "sg_joy0", "joy2_read", NULL, 0);
        comp->joy1 = joy1;
        comp->joy2 = joy2;
        if (p == 0xC0u) {
            /* SG-1000/SMS-compatible port A read:
               bits 0..5 = joy1 U/D/L/R/B1/B2, bits 6..7 = joy2 U/D. */
            value = (uint8_t)((joy1 & 0x3Fu) | (uint8_t)((joy2 << 6) & 0xC0u));
        } else if (p == 0xC1u) {
            /* SG-1000/SMS-compatible port B/misc read:
               bits 0..3 = joy2 L/R/B1/B2 (from joy2 bits 2..5),
               bit 4 = reset line (active low), bits 5..7 = high. */
            value = (uint8_t)(((joy2 >> 2) & 0x0Fu) | 0xF0u);
            if ((joy2 & 0x10u) == 0u) {
                value = (uint8_t)(value & (uint8_t)~0x10u);
            }
        }
        return value;
    }

    return value;
}

void z80_write_port(CPUState *cpu, uint16_t port, uint8_t value) {

    {
        ComponentState_sg_vdp0 *comp = &cpu->comp_sg_vdp0;
        cpu->active_component_id = "sg_vdp0";
        uint8_t *vram = comp->vram;
        if (vram == NULL) return;
        uint8_t p = (uint8_t)(((uint16_t)port) & 0x00C1u);
        if (p == 0x80u) {
            vram[(uint16_t)(comp->vdp_addr & 0x3FFFu)] = value;
            comp->vdp_addr = (uint16_t)((comp->vdp_addr + 1u) & 0x3FFFu);
            comp->render_dirty = 1u;
        } else if (p == 0x81u) {
            if (comp->control_phase == 0u) {
                comp->control_latch = value;
                comp->control_phase = 1u;
            } else {
                uint8_t cmd = value;
                uint16_t addr = (uint16_t)(((uint16_t)(cmd & 0x3Fu) << 8) | comp->control_latch);
                if ((cmd & 0x80u) != 0u) {
                    uint8_t reg_idx = (uint8_t)(cmd & 0x07u);
                    uint8_t reg_val = comp->control_latch;
                    switch (reg_idx) {
                        case 0u: comp->reg0 = reg_val; break;
                        case 1u: comp->reg1 = reg_val; break;
                        case 2u: comp->reg2 = reg_val; break;
                        case 3u: comp->reg3 = reg_val; break;
                        case 4u: comp->reg4 = reg_val; break;
                        case 5u: comp->reg5 = reg_val; break;
                        case 6u: comp->reg6 = reg_val; break;
                        case 7u: comp->reg7 = reg_val; break;
                        default: break;
                    }
                    comp->render_dirty = 1u;
                } else if ((cmd & 0x40u) != 0u) {
                    comp->vdp_addr = (uint16_t)(addr & 0x3FFFu);
                } else {
                    comp->vdp_addr = (uint16_t)(addr & 0x3FFFu);
                    comp->read_buffer = vram[(uint16_t)(comp->vdp_addr & 0x3FFFu)];
                    comp->vdp_addr = (uint16_t)((comp->vdp_addr + 1u) & 0x3FFFu);
                }
                comp->control_phase = 0u;
            }
        }
    }
    {
        ComponentState_sms_psg0 *comp = &cpu->comp_sms_psg0;
        cpu->active_component_id = "sms_psg0";
        uint8_t p = (uint8_t) (((uint16_t) port) & 0x00C1u);

        if (p != 0x40u && p != 0x41u) {
            return;
        }

        {
            uint8_t v = value;

            if ((v & 0x80u) != 0u) {
                uint8_t ch = (uint8_t) ((v >> 5) & 0x03u);
                uint8_t is_vol = (uint8_t) ((v >> 4) & 0x01u);
                uint8_t nib = (uint8_t) (v & 0x0Fu);

                comp->latched_channel = ch;
                comp->latched_is_volume = is_vol;

                if (is_vol != 0u) {
                    switch (ch) {
                        case 0u:
                            comp->vol0 = nib;
                            break;

                        case 1u:
                            comp->vol1 = nib;
                            break;

                        case 2u:
                            comp->vol2 = nib;
                            break;

                        case 3u:
                            comp->vol3 = nib;
                            break;

                        default:
                            break;
                    }
                } else if (ch < 3u) {
                    if (ch == 0u) {
                        comp->tone0 = (uint16_t) ((comp->tone0 & 0x03F0u) | (uint16_t) nib);
                    } else if (ch == 1u) {
                        comp->tone1 = (uint16_t) ((comp->tone1 & 0x03F0u) | (uint16_t) nib);
                    } else {
                        comp->tone2 = (uint16_t) ((comp->tone2 & 0x03F0u) | (uint16_t) nib);
                    }
                } else {
                    comp->noise_reg = (uint8_t) (nib & 0x07u);
                    comp->lfsr = 0x8000u;
                    comp->noise_phase = 0u;
                    comp->noise_out = 0u;
                    comp->noise_ctr = 0u;
                }
            } else {
                uint8_t ch = comp->latched_channel;

                if (comp->latched_is_volume != 0u) {
                    uint8_t nib = (uint8_t) (v & 0x0Fu);

                    switch (ch) {
                        case 0u:
                            comp->vol0 = nib;
                            break;

                        case 1u:
                            comp->vol1 = nib;
                            break;

                        case 2u:
                            comp->vol2 = nib;
                            break;

                        case 3u:
                            comp->vol3 = nib;
                            break;

                        default:
                            break;
                    }
                } else if (ch < 3u) {
                    uint16_t hi = (uint16_t) (v & 0x3Fu);

                    if (ch == 0u) {
                        comp->tone0 = (uint16_t) ((comp->tone0 & 0x000Fu) | (uint16_t) (hi << 4));
                    } else if (ch == 1u) {
                        comp->tone1 = (uint16_t) ((comp->tone1 & 0x000Fu) | (uint16_t) (hi << 4));
                    } else {
                        comp->tone2 = (uint16_t) ((comp->tone2 & 0x000Fu) | (uint16_t) (hi << 4));
                    }
                } else {
                    comp->noise_reg = (uint8_t) (v & 0x07u);
                    comp->lfsr = 0x8000u;
                    comp->noise_phase = 0u;
                    comp->noise_out = 0u;
                    comp->noise_ctr = 0u;
                }
            }
        }
    }
    if (port >= cpu->port_size) return;
    cpu->port_memory[port] = value;


}

/* ===== Interrupts ===== */
void z80_interrupt(CPUState *cpu, uint8_t vector) {
    cpu->interrupt_vector = vector;
    cpu->interrupt_pending = true;
    cpu_irq_trace(cpu, "request", vector, 0u);
}

void z80_set_interrupt_mode(CPUState *cpu, uint8_t mode) {
    cpu->interrupt_mode = mode;
}

void z80_set_irq(CPUState *cpu, bool enabled) {
    cpu->interrupts_enabled = enabled;
}
